local key = { 126, 133, 77, 98, 130, 245, 69, 14, 194, 32, 15, 146, 202, 165, 190, 24, 67, 130, 12, 27, 206, 75, 209, 10, 131, 4, 249, 153, 217, 229, 41, 228, 193, 111, 108, 180, 219, 109, 107, 29, 132, 155, 54, 205, 99, 10, 161, 35, 65, 1, 171, 69, 9, 26, 99, 226, 113, 215, 111, 231, 216, 232, 63, 198 }
local alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local values = {}
for index = 1, #alphabet do
	values[alphabet:sub(index, index)] = index - 1
end
local bxor = bit32 and bit32.bxor or function(a, b)
	local result, bitValue = 0, 1
	while a > 0 or b > 0 do
		local aBit = a % 2
		local bBit = b % 2
		if aBit ~= bBit then
			result = result + bitValue
		end
		a = math.floor(a / 2)
		b = math.floor(b / 2)
		bitValue = bitValue * 2
	end
	return result
end
local function decodeBase64(data)
	data = tostring(data or ""):gsub("%s+", "")
	local output = {}
	for index = 1, #data, 4 do
		local a = values[data:sub(index, index)] or 0
		local b = values[data:sub(index + 1, index + 1)] or 0
		local cChar = data:sub(index + 2, index + 2)
		local dChar = data:sub(index + 3, index + 3)
		local c = values[cChar] or 0
		local d = values[dChar] or 0
		local combined = (a * 262144) + (b * 4096) + (c * 64) + d
		output[#output + 1] = string.char(math.floor(combined / 65536) % 256)
		if cChar ~= "=" then
			output[#output + 1] = string.char(math.floor(combined / 256) % 256)
		end
		if dChar ~= "=" then
			output[#output + 1] = string.char(combined % 256)
		end
	end
	return table.concat(output)
end
local function decrypt(data)
	local output = table.create and table.create(#data) or {}
	for index = 1, #data do
		local value = string.byte(data, index)
		output[index] = string.char(bxor(value, key[((index - 1) % #key) + 1]))
	end
	return table.concat(output)
end
local loader = (typeof(loadstring) == "function" and loadstring) or load
assert(loader, "Julia Hub requires loadstring support")
local chunk, err = loader(decrypt(decodeBase64(payload)))
assert(chunk, err)
return chunk()
